INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: IIT Kharagpur was the first IIT established in India in 1951.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: The campus is spread over 2100 acres, making it one of the largest IIT campuses in India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: It has 21 Halls of Residence - 16 for boys and 5 for girls.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: Around 10,000 students study at IIT Kharagpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: The campus is self-contained with restaurants, banks, stadiums, gym, hospital, post office, market, swimming pool, and schools all within campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: The main building was established in 1951 and is the face of IIT Kharagpur.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: The campus has a 2.2 km road (called 2.2 road) that connects majority of the campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: Notable alumni include Sundar Pichai (CEO of Google), who graduated from the Metallurgical and Materials Engineering department.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'overview', 'Overview > Facts: The campus was once a British detention camp, and the Nehru Museum preserves this history with a real aircraft on display.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Hostel: LBS Hall (Lal Bahadur Shastri Hall)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Sharing: 3-share per room');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Floors: 4');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Allotment: Rooms are posted on the hostel building as soon as students complete JoSAA counselling and arrive at campus. No separate application needed.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Facts: LBS Hall is one of the newer hostels, completed around 2010.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Facts: The hostel has a night canteen that operates from 9:30 PM to 2:30 AM on the 2nd floor mess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Facts: There is a Nescafe shop beside the main gate open from 9 AM to 3 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > First Year > Facts: LBS mess food is considered below average by many students, though the night canteen is rated well.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Allotment: Random allotment through ERP system. Students have no choice in which hall they get.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Continuity: Once allotted a hall in 2nd year, students stay in the same hall for 3rd and 4th year. Room number may change but hall remains same.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Sharing Progression: 2nd year: as per hall default. 3rd year: may get upgraded to 2-sharing. 4th year: may get single room.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: MMM Hall (Pandit Madan Mohan Malviya Hall). sharing: 2-share. floors: 5-6. lift: True. capacity: 2000+ boarders. note: Largest hall in IIT Kharagpur. Completed in 2010');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Mess food quality is debatable - some say it is one of the worst, others say it is decent');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: LLR Hall (Lala Lajpat Rai Hall). sharing: 1-share (single). floors: 4. lift: False. note: Single rooms - considered lucky allotment.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: Rajendra Prasad Hall (RP Hall). sharing: 3-share. floors: 4. lift: False. note: One of the first established halls in IIT Kharagpur. Has its own mess with decent food.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: Radhakrishnan Hall. sharing: 3-share. floors: 4. lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: Meghnad Saha Hall. sharing: 1-share (single). floors: 4. lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: Patel Hall. note: Built in 1952, this is the first IIT hostel in all of India.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_boys', 'Hostels Boys > Second Year Onwards > Hostels - name: Azad Hall. note: Has good facilities and mess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > First Year > Hostel: SNVH (Sister Niveditha Vidyarthi Hall)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > First Year > Sharing: 3-share per room');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > First Year > Floors: 4');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > First Year > Lift: False');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > Second Year Onwards > Allotment: Random via ERP system, same as boys.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > Second Year Onwards > Continuity: Same hall from 2nd to 4th year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > Second Year Onwards > Hostels - name: Rani Laxmibai Hall. sharing: 2-share');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > Second Year Onwards > Hostels - name: Mother Teresa Hall. sharing: 2-share. note: Located on 2.2 road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostels_girls', 'Hostels Girls > Second Year Onwards > Hostels - name: Sarojini Naidu Hall. sharing: 2-share. note: Located near the clock tower on 2.2 road.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Wifi: Unlimited. YouTube, Instagram, and all websites/apps work without restriction.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Lan: Available in all hostels. Students need to buy their own LAN cable.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Gate Timing: No separate hostel gate timing. Main college gate closes at 11 PM - cannot leave after 11 PM. If you left before 11 PM, the gate opens whenever you return. Gate opens at 5 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > No Curfew Note: There is no concept of in-time in hostels. Students can freely move around campus at night. The food court stays open until 4 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Delivery: Zomato and Swiggy deliveries are allowed. Delivery comes to the gate inside the college campus, just downstairs from the hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Furniture: Bed, table, chair, fan, cupboard, high-speed LAN port, lights, and adequate electricity ports are provided. Quantity varies by sharing type.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Room Note: Rooms are spacious enough for 3 students in triple sharing. Storage space is limited - only a small cupboard for shared rooms.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Mosquito Nets: Available in some hostels.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Toilets: Western-style toilets available in newer hostels like LBS and MMM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'hostel_common', 'Hostel Common > Balcony: Some hostels have balconies with nice views.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > System: Each hostel has its own attached mess. No central mess.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Schedule: Menu changes monthly. Mess committees actively take feedback from students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Cuisine: Both North Indian and South Indian cuisine. Vegetarian and non-vegetarian options available.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Specials > Wednesday: Chicken served in almost all hostel messes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Specials > Friday: Some hostels serve biryani, others serve chicken.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Specials > Sunday: Some hostels serve chicken, others serve biryani.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Quality: Varies greatly by hostel. Generally rated 2-4 out of 5. Common complaint is inconsistency. LBS mess is considered below average, while some other halls like RP have decent food.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Alternatives: Even if mess food is not great, there are many restaurants on campus - phone restaurants, heritage, PFC, and many more. Students from South India or North India can find food they are comfortable with.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Night Canteen: Most hostels have night canteens that operate late into the night.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'mess', 'Mess > Food Court: Stays open until 4 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Tech Market: IIT Kharagpur has a self-sustained market called Tech Market within campus where students buy groceries, fruits, and daily necessities.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Restaurants: Billoo''s - Famous for Punjabi food');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Restaurants: Dreamland-Sahara');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Restaurants: Phone - Popular restaurant');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Restaurants: PFC (Fried chicken)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Chains: Cafe Coffee Day, Baskin Robbins, and Subway are available on campus. Subway offers 30-40% discount for IIT students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Shiru Cafe: A Japanese-run cafe near Nalanda complex that serves free coffee, mango juice, and orange juice. They collect student data (roll number, email, phone) for marketing purposes in exchange.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Tikka: Food stall near the back gate where you can get samosa, tiffins, noodles, fast food.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'food_outside', 'Food Outside > Night Options: Night canteens in hostels, food court open till 4 AM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'laundry', 'Laundry > Method: Washing machines available on every floor in every hostel.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'laundry', 'Laundry > Cost: Free to use.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Tata Sports Complex: Largest ground in IIT Kharagpur. Has 2 football grounds and 2 cricket grounds. Also has a running/jogging track. Training nets for cricket practice.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Jnan Ghosh Stadium: Athletics stadium on par with national/international standards. Has synthetic running track.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Gandhi Maidan: Hockey ground.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Aquatic Center: Fully modernized swimming pool. Students can take membership.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Hostel Gym: Every hostel has its own gym which is completely free. Open 24/7.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Gymkhana Gym: Larger gym at Technology Students Gymkhana. Costs Rs 1000 per year. Available for both boys and girls. Timing: 7 AM to 11 AM, 6 PM to 9 PM.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Other Sports: Cricket, football, basketball, tennis, badminton, athletics, karate, weightlifting (dedicated room).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'sports_gym', 'Sports Gym > Sports Manageability: Sports and academics are easily manageable. Students wake up at 5-6 AM for morning sports or play in late afternoon after classes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > Campus Bus: Each hostel has bus service that regularly transports students from hostels to department buildings.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > Cycling: Primary mode of transport. Almost all students buy cycles when they arrive. Essential due to 2100 acre campus size.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > Cycling Note: Make sure you learn cycling before coming to campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > Nearest Railway: Kharagpur Junction - 5 km from campus, 10-20 minutes. Auto Rs 100, Taxi Rs 200.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > Nearest Airport: Netaji Subhas Chandra Bose International Airport (CCU), Kolkata - 140 km, 2.5 hours by taxi.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'transport', 'Transport > To Kolkata: 120-130 km. Trains every 30 minutes from Kharagpur Junction to Howrah, taking 1.5-2.5 hours.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics > Nalanda Complex: One of the biggest classroom complexes in India with capacity for over 30,000 students. Rooms equipped with centralized AC. Two types of classrooms: NR (Nalanda Rectangular) and NC (Nalanda Circular).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics > Central Library: Largest technical library in Asia with over 3.1 lakh volumes including novels, publishing journals, textbooks, and reference books. Open to all students. New books added weekly.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics > Departments: All major engineering departments available. Some unique departments: Ocean Engineering and Naval Architecture (only at IIT KGP and IIT Madras), Cryogenic Engineering (only at IIT KGP), Industrial Systems Engineering (only at IIT KGP).');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics > Attendance: 75% mandatory attendance policy was removed recently. Current policy is 0% attendance requirement. However, internal marks increased from 20 to 40. Surprise tests and surprise attendance may count towards internals.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'academics', 'Academics > Kalpana Chawla Cell: Kalpana Chawla Space Technology Cell - IIT Kharagpur''s direct point of contact with ISRO.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'fests', 'Fests > Kshitij: Annual techno-management fest. One of the largest tech fests in Asia. Happens in January/February.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'fests', 'Fests > Spring Fest: Annual social and cultural festival. First edition in 1960. 66th edition held in January 2025. Footfall of over 80,000 people. Events include dance, music, dramatics, photography, literature, quizzing, food fest, fine arts.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'fests', 'Fests > Shaurya: Sports fest.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'fests', 'Fests > Scale: Over 10,000 people from all over India attend. Guest sessions, events, workshops, competitions with prize money.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Eligibility: 3rd year ending students (entering 4th year) can stand for elections.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Roles: Vice President (VP)');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Roles: General Secretary of Sports and Games');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Roles: General Secretary of Technology');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Roles: General Secretary of Gymkhana');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Process: Students prepare proposals with complete workout plan including fund sources and permissions. They face a seniors panel and need to convince an audience of 6000-7000 people. The election process involves intense preparation and public speaking.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Hall Elections: Each hall also has internal elections. Winning requires convincing students and building support.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'elections', 'Elections > Maturity Note: The election process is known to bring remarkable maturity in students - a person who joined as a fresher in BTech develops significant leadership and public speaking skills by 3rd-4th year.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'medical', 'Medical > Hospital: BC Roy Technology Hospital on campus. Available for all faculty, staff, and students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'medical', 'Medical > Access: Free for students.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'medical', 'Medical > Location: Near the tech market.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > Weekend Trips - name: Kolkata. distance: 120-130 km. time: 1.5-2.5 hours by train. note: Most popular weekend destination. Trains every 30 minutes.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > Weekend Trips - name: Digha Beach. distance: 101 km. time: 1.5-2 hours by road');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > Long Trips - name: Puri Jagannath Temple. distance: 373 km. time: 5.5 hours by road/train');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > Long Trips - name: Varanasi. distance: 710 km. time: 13 hours by train');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'location_nearby', 'Location Nearby > Long Trips - name: Darjeeling. distance: 650-670 km. time: 10 hours by road');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Tech Market: Self-sustained market with barber shops, grocery stores, fruit/vegetable shops, sports shops, electronic shops, salons.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Bc Roy Hospital: Campus hospital for students and faculty.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Swimming Pool: Available with membership.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Netaji Auditorium: Film screenings every week for students. Also hosts events, dance programs, musical nights.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Kalidas Auditorium: Another auditorium for events, ceremonies, and fests.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Technology Guest House: Available for parents visiting campus and for alumni.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Lakeside: Beautiful lake behind the gymkhana with an island connected by a bridge. Popular spot for birthday celebrations.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Robotics Room: Dedicated facility for robotics enthusiasts.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Vinod Gupta School: School of Management for MBA, gifted by alumni Vinod Gupta. Advanced architecture.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Nehru Museum: Former British detention camp converted to museum. Has a real aircraft on display. Must-visit with parents.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Rajiv Gandhi Law School: Law school within IIT Kharagpur campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Banks Atms: Available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Post Office: Available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'campus_facilities', 'Campus Facilities > Railway Reservation: Counter available on campus.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe > Overall: IIT Kharagpur is a mixture of everything - academics, sports, library, fests, hall activities, and variety activities.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe > Clubs: Robotics, coding, dance, music, dramatics, and many more technical and cultural clubs.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe > Night Life: No hostel curfew. Food court open till 4 AM. Birthday celebrations at lakeside at midnight.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe > Language: Mix of Hindi and English. Bengali is local language but Hindi/English is sufficient.');
INSERT INTO knowledge_chunks (college, section, chunk_text) VALUES ('IIT Kharagpur', 'culture_vibe', 'Culture Vibe > Senior Junior: Strong hall culture and bonding. Elections and hall activities bring students together.');